import { useEffect, useMemo, useState } from 'react';
import {
  fetchManagedDiningCatalog,
  fetchManagedRooms,
  getManagedDiningCatalog,
  getManagedRooms,
  saveManagedDiningCatalog,
  saveManagedRooms,
} from '../utils/adminCatalog';

const emptyRoomForm = {
  name: '',
  price: '',
  image: '',
  description: '',
  overview: '',
  guests: '',
  size: '',
  bed: '',
  idealFor: '',
  features: '',
};

const emptyMenuForm = {
  categoryTitle: '',
  categoryDescription: '',
  name: '',
  price: '',
  image: '',
};

const emptyFeaturedForm = {
  title: '',
  price: '',
  image: '',
  tag: '',
  description: '',
};

function AdminCatalogManager() {
  const [rooms, setRooms] = useState(() => getManagedRooms());
  const [diningCatalog, setDiningCatalog] = useState(() => getManagedDiningCatalog());
  const [roomForm, setRoomForm] = useState(emptyRoomForm);
  const [menuForm, setMenuForm] = useState(emptyMenuForm);
  const [featuredForm, setFeaturedForm] = useState(emptyFeaturedForm);
  const [editingRoomName, setEditingRoomName] = useState('');
  const [editingMenuKey, setEditingMenuKey] = useState('');
  const [editingFeaturedTitle, setEditingFeaturedTitle] = useState('');
  const [success, setSuccess] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(true);

  const sortedCategories = useMemo(
    () => [...diningCatalog.categories].sort((first, second) => first.title.localeCompare(second.title)),
    [diningCatalog.categories]
  );

  useEffect(() => {
    let active = true;

    async function loadCatalog() {
      try {
        const [nextRooms, nextDiningCatalog] = await Promise.all([
          fetchManagedRooms(),
          fetchManagedDiningCatalog(),
        ]);

        if (!active) {
          return;
        }

        setRooms(nextRooms);
        setDiningCatalog(nextDiningCatalog);
      } catch (requestError) {
        if (!active) {
          return;
        }

        setError('Unable to sync admin catalog with the server. Using cached content.');
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    }

    loadCatalog();

    return () => {
      active = false;
    };
  }, []);

  const commitRooms = async (nextRooms, message) => {
    const savedRooms = await saveManagedRooms(nextRooms);
    setRooms(savedRooms);
    setSuccess(message);
    setError('');
  };

  const commitDining = async (nextCatalog, message) => {
    const savedCatalog = await saveManagedDiningCatalog(nextCatalog);
    setDiningCatalog(savedCatalog);
    setSuccess(message);
    setError('');
  };

  const handleRoomSubmit = async (event) => {
    event.preventDefault();

    const nextRoom = {
      ...roomForm,
      features: roomForm.features
        .split(',')
        .map((feature) => feature.trim())
        .filter(Boolean),
    };

    const nextRooms = editingRoomName
      ? rooms.map((room) => (room.name === editingRoomName ? nextRoom : room))
      : [...rooms, nextRoom];

    await commitRooms(nextRooms, editingRoomName ? 'Room updated.' : 'Room added.');
    setRoomForm(emptyRoomForm);
    setEditingRoomName('');
  };

  const handleMenuSubmit = async (event) => {
    event.preventDefault();

    const normalizedCategoryTitle = menuForm.categoryTitle.trim();
    const normalizedCategoryDescription = menuForm.categoryDescription.trim();
    const nextItem = {
      name: menuForm.name.trim(),
      price: menuForm.price.trim(),
      image: menuForm.image.trim(),
    };

    const [editingCategoryTitle, editingItemName] = editingMenuKey.split(':');

    const nextCategories = [...diningCatalog.categories]
      .map((category) => ({ ...category, items: [...category.items] }))
      .map((category) =>
        category.title === editingCategoryTitle
          ? {
              ...category,
              items: category.items.filter((item) => item.name !== editingItemName),
            }
          : category
      )
      .filter((category) => category.items.length > 0);

    const targetCategoryIndex = nextCategories.findIndex((category) => category.title === normalizedCategoryTitle);

    if (targetCategoryIndex >= 0) {
      nextCategories[targetCategoryIndex] = {
        ...nextCategories[targetCategoryIndex],
        description: normalizedCategoryDescription || nextCategories[targetCategoryIndex].description,
        items: [...nextCategories[targetCategoryIndex].items, nextItem],
      };
    } else {
      nextCategories.push({
        title: normalizedCategoryTitle,
        description: normalizedCategoryDescription || 'Freshly managed menu selections from the admin panel.',
        items: [nextItem],
      });
    }

    const cleanedCategories = nextCategories
      .map((category) => ({ ...category, items: category.items.filter((item) => item.name) }))
      .filter((category) => category.items.length > 0);

    await commitDining(
      {
        ...diningCatalog,
        categories: cleanedCategories,
      },
      editingMenuKey ? 'Menu item updated.' : 'Menu item added.'
    );

    setMenuForm(emptyMenuForm);
    setEditingMenuKey('');
  };

  const handleFeaturedSubmit = async (event) => {
    event.preventDefault();

    const nextPlate = { ...featuredForm };
    const nextFeaturedPlates = editingFeaturedTitle
      ? diningCatalog.featuredPlates.map((plate) => (plate.title === editingFeaturedTitle ? nextPlate : plate))
      : [...diningCatalog.featuredPlates, nextPlate];

    await commitDining(
      {
        ...diningCatalog,
        featuredPlates: nextFeaturedPlates,
      },
      editingFeaturedTitle ? 'Featured plate updated.' : 'Featured plate added.'
    );

    setFeaturedForm(emptyFeaturedForm);
    setEditingFeaturedTitle('');
  };

  const startRoomEdit = (room) => {
    setRoomForm({
      ...room,
      features: room.features.join(', '),
    });
    setEditingRoomName(room.name);
  };

  const deleteRoom = async (roomName) => {
    await commitRooms(
      rooms.filter((room) => room.name !== roomName),
      'Room removed.'
    );
    if (editingRoomName === roomName) {
      setRoomForm(emptyRoomForm);
      setEditingRoomName('');
    }
  };

  const startMenuEdit = (category, item) => {
    setMenuForm({
      categoryTitle: category.title,
      categoryDescription: category.description,
      name: item.name,
      price: item.price,
      image: item.image,
    });
    setEditingMenuKey(`${category.title}:${item.name}`);
  };

  const deleteMenuItem = async (categoryTitle, itemName) => {
    const nextCategories = diningCatalog.categories
      .map((category) =>
        category.title === categoryTitle
          ? {
              ...category,
              items: category.items.filter((item) => item.name !== itemName),
            }
          : category
      )
      .filter((category) => category.items.length > 0);

    await commitDining(
      {
        ...diningCatalog,
        categories: nextCategories,
      },
      'Menu item removed.'
    );
  };

  const startFeaturedEdit = (plate) => {
    setFeaturedForm(plate);
    setEditingFeaturedTitle(plate.title);
  };

  const deleteFeatured = async (title) => {
    await commitDining(
      {
        ...diningCatalog,
        featuredPlates: diningCatalog.featuredPlates.filter((plate) => plate.title !== title),
      },
      'Featured plate removed.'
    );
  };

  return (
    <section className="card shadow p-4">
      <div className="mb-4">
        <h3 className="text-primary mb-1">Content Management</h3>
        <p className="text-muted mb-0">
          Add, modify, and remove rooms, menu items, and featured dishes from the hotel experience.
        </p>
      </div>

      {success && <div className="alert alert-success">{success}</div>}
      {error && <div className="alert alert-warning">{error}</div>}
      {loading && <div className="alert alert-info">Syncing catalog from server...</div>}

      <div className="row g-4">
        <div className="col-xl-6">
          <div className="card border-0 bg-light h-100">
            <div className="card-body">
              <h4 className="mb-3">Room Inventory</h4>
              <form onSubmit={handleRoomSubmit} className="mb-4">
                <div className="row g-3">
                  {Object.entries({
                    name: 'Room Name',
                    price: 'Price',
                    image: 'Image URL',
                    description: 'Short Description',
                    overview: 'Overview',
                    guests: 'Guests',
                    size: 'Size',
                    bed: 'Bed Type',
                    idealFor: 'Ideal For',
                    features: 'Features',
                  }).map(([key, label]) => (
                    <div className={key === 'description' || key === 'overview' || key === 'features' ? 'col-12' : 'col-md-6'} key={key}>
                      <label className="form-label">{label}</label>
                      {key === 'description' || key === 'overview' ? (
                        <textarea
                          className="form-control"
                          rows="3"
                          value={roomForm[key]}
                          onChange={(event) => setRoomForm((current) => ({ ...current, [key]: event.target.value }))}
                          required
                        />
                      ) : (
                        <input
                          className="form-control"
                          value={roomForm[key]}
                          onChange={(event) => setRoomForm((current) => ({ ...current, [key]: event.target.value }))}
                          placeholder={key === 'features' ? 'Comma separated features' : ''}
                          required
                        />
                      )}
                    </div>
                  ))}
                </div>

                <div className="d-flex gap-2 mt-3">
                  <button type="submit" className="btn btn-primary">
                    {editingRoomName ? 'Update Room' : 'Add Room'}
                  </button>
                  {editingRoomName && (
                    <button
                      type="button"
                      className="btn btn-outline-secondary"
                      onClick={() => {
                        setRoomForm(emptyRoomForm);
                        setEditingRoomName('');
                      }}
                    >
                      Cancel
                    </button>
                  )}
                </div>
              </form>

              <div className="d-grid gap-3">
                {rooms.map((room) => (
                  <div className="border rounded p-3 bg-white" key={room.name}>
                    <div className="d-flex justify-content-between align-items-start gap-3">
                      <div>
                        <h5 className="mb-1">{room.name}</h5>
                        <p className="text-muted mb-1">{room.price}</p>
                        <p className="mb-2">{room.description}</p>
                      </div>
                      <div className="d-flex gap-2">
                        <button type="button" className="btn btn-sm btn-outline-primary" onClick={() => startRoomEdit(room)}>
                          Modify
                        </button>
                        <button type="button" className="btn btn-sm btn-outline-danger" onClick={() => deleteRoom(room.name)}>
                          Remove
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>

        <div className="col-xl-6">
          <div className="card border-0 bg-light mb-4">
            <div className="card-body">
              <h4 className="mb-3">Dining Menu</h4>
              <form onSubmit={handleMenuSubmit}>
                <div className="row g-3">
                  <div className="col-md-6">
                    <label className="form-label">Category Title</label>
                    <input className="form-control" value={menuForm.categoryTitle} onChange={(event) => setMenuForm((current) => ({ ...current, categoryTitle: event.target.value }))} required />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label">Category Description</label>
                    <input className="form-control" value={menuForm.categoryDescription} onChange={(event) => setMenuForm((current) => ({ ...current, categoryDescription: event.target.value }))} />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label">Food Name</label>
                    <input className="form-control" value={menuForm.name} onChange={(event) => setMenuForm((current) => ({ ...current, name: event.target.value }))} required />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label">Price</label>
                    <input className="form-control" value={menuForm.price} onChange={(event) => setMenuForm((current) => ({ ...current, price: event.target.value }))} placeholder="KSh 1,250" required />
                  </div>
                  <div className="col-12">
                    <label className="form-label">Image URL</label>
                    <input className="form-control" value={menuForm.image} onChange={(event) => setMenuForm((current) => ({ ...current, image: event.target.value }))} required />
                  </div>
                </div>

                <div className="d-flex gap-2 mt-3">
                  <button type="submit" className="btn btn-primary">
                    {editingMenuKey ? 'Update Food Item' : 'Add Food Item'}
                  </button>
                  {editingMenuKey && (
                    <button type="button" className="btn btn-outline-secondary" onClick={() => { setMenuForm(emptyMenuForm); setEditingMenuKey(''); }}>
                      Cancel
                    </button>
                  )}
                </div>
              </form>

              <div className="d-grid gap-3 mt-4">
                {sortedCategories.map((category) => (
                  <div className="border rounded p-3 bg-white" key={category.title}>
                    <h5 className="mb-1">{category.title}</h5>
                    <p className="text-muted">{category.description}</p>
                    {category.items.map((item) => (
                      <div className="d-flex justify-content-between align-items-start border-top pt-2 mt-2" key={item.name}>
                        <div>
                          <strong>{item.name}</strong>
                          <div className="text-muted">{item.price}</div>
                        </div>
                        <div className="d-flex gap-2">
                          <button type="button" className="btn btn-sm btn-outline-primary" onClick={() => startMenuEdit(category, item)}>
                            Modify
                          </button>
                          <button type="button" className="btn btn-sm btn-outline-danger" onClick={() => deleteMenuItem(category.title, item.name)}>
                            Remove
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                ))}
              </div>
            </div>
          </div>

          <div className="card border-0 bg-light">
            <div className="card-body">
              <h4 className="mb-3">Featured Dishes</h4>
              <form onSubmit={handleFeaturedSubmit}>
                <div className="row g-3">
                  <div className="col-md-6">
                    <label className="form-label">Title</label>
                    <input className="form-control" value={featuredForm.title} onChange={(event) => setFeaturedForm((current) => ({ ...current, title: event.target.value }))} required />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label">Price</label>
                    <input className="form-control" value={featuredForm.price} onChange={(event) => setFeaturedForm((current) => ({ ...current, price: event.target.value }))} required />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label">Tag</label>
                    <input className="form-control" value={featuredForm.tag} onChange={(event) => setFeaturedForm((current) => ({ ...current, tag: event.target.value }))} required />
                  </div>
                  <div className="col-md-6">
                    <label className="form-label">Image URL</label>
                    <input className="form-control" value={featuredForm.image} onChange={(event) => setFeaturedForm((current) => ({ ...current, image: event.target.value }))} required />
                  </div>
                  <div className="col-12">
                    <label className="form-label">Description</label>
                    <textarea className="form-control" rows="3" value={featuredForm.description} onChange={(event) => setFeaturedForm((current) => ({ ...current, description: event.target.value }))} required />
                  </div>
                </div>

                <div className="d-flex gap-2 mt-3">
                  <button type="submit" className="btn btn-primary">
                    {editingFeaturedTitle ? 'Update Featured Dish' : 'Add Featured Dish'}
                  </button>
                  {editingFeaturedTitle && (
                    <button type="button" className="btn btn-outline-secondary" onClick={() => { setFeaturedForm(emptyFeaturedForm); setEditingFeaturedTitle(''); }}>
                      Cancel
                    </button>
                  )}
                </div>
              </form>

              <div className="d-grid gap-3 mt-4">
                {diningCatalog.featuredPlates.map((plate) => (
                  <div className="border rounded p-3 bg-white" key={plate.title}>
                    <div className="d-flex justify-content-between align-items-start gap-3">
                      <div>
                        <h5 className="mb-1">{plate.title}</h5>
                        <p className="text-muted mb-1">{plate.tag} • {plate.price}</p>
                        <p className="mb-0">{plate.description}</p>
                      </div>
                      <div className="d-flex gap-2">
                        <button type="button" className="btn btn-sm btn-outline-primary" onClick={() => startFeaturedEdit(plate)}>
                          Modify
                        </button>
                        <button type="button" className="btn btn-sm btn-outline-danger" onClick={() => deleteFeatured(plate.title)}>
                          Remove
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default AdminCatalogManager;
